"use client"

import Link from "next/link"
import { usePathname } from "next/navigation"
import { BarChart3, Building2, Calendar, Settings, Users, ChevronDown, Home, FileText } from "lucide-react"
import { useState, useEffect } from "react"

interface NavItem {
  href?: string
  label: string
  icon: React.ComponentType<{ className?: string }>
  subItems?: NavItem[]
}

const navItems: NavItem[] = [
  { href: "/dashboard", label: "Dashboard", icon: BarChart3 },
  {
    label: "Property",
    icon: Building2,
    subItems: [
      { href: "/execution", label: "Property List", icon: Home },
      { href: "#", label: "Property Detail", icon: FileText },
    ],
  },

  { href: "/rules", label: "Rules", icon: Settings },
  { href: "/users", label: "Users", icon: Users },
]

interface NavItemProps {
  item: NavItem
  isActive: boolean
  pathname: string
}

function NavItemComponent({ item, isActive, pathname }: NavItemProps) {
  const [isOpen, setIsOpen] = useState(false)
  const Icon = item.icon
  const hasSubItems = item.subItems && item.subItems.length > 0

  // Open submenu when on execution routes
  useEffect(() => {
    if (item.label === "Property" && pathname.includes("/execution")) {
      setIsOpen(true)
    }
  }, [pathname, item.label])

  const handleToggle = (e: React.MouseEvent) => {
    e.preventDefault()
    
    // If it's a parent with subItems and not yet opened, navigate to first subitem
    if (hasSubItems && !isOpen && item.label === "Property") {
      const firstSubItem = item.subItems?.[0]
      if (firstSubItem?.href) {
        window.location.href = firstSubItem.href
        return
      }
    }
    
    setIsOpen(!isOpen)
  }

  if (hasSubItems) {
    return (
      <div>
        <button
          onClick={handleToggle}
          className={`w-full flex items-center gap-3 px-4 py-2 rounded-lg transition-colors font-medium text-sm ${
            isActive
              ? "bg-blue-600 text-white"
              : "text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700"
          }`}
        >
          <Icon className="w-5 h-5" />
          <span className="flex-1 text-left">{item.label}</span>
          <ChevronDown
            className={`w-4 h-4 transition-transform duration-200 ${
              isOpen ? "rotate-180" : ""
            }`}
          />
        </button>

        {/* Submenu */}
        {isOpen && (
          <div className="mt-1 space-y-1 pl-4">
            {item?.subItems?.map((subItem) => {
              const SubIcon = subItem.icon
              const isSubActive = pathname === subItem.href || 
                (subItem.label === "Property Detail" && pathname.match(/^\/execution\/[a-f0-9]{24}$/))

              return (
                <Link
                  key={subItem.label}
                  href={subItem.href || "#"}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-colors text-sm ${
                    isSubActive
                      ? "bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300 font-medium"
                      : "text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-200"
                  }`}
                >
                  <SubIcon className="w-4 h-4" />
                  <span>{subItem.label}</span>
                </Link>
              )
            })}
          </div>
        )}
      </div>
    )
  }

  return (
    <Link
      href={item.href || "#"}
      className={`flex items-center gap-3 px-4 py-2 rounded-lg transition-colors font-medium text-sm ${
        isActive
          ? "bg-blue-600 text-white"
          : "text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700"
      }`}
    >
      <Icon className="w-5 h-5" />
      <span>{item.label}</span>
    </Link>
  )
}

export function Sidebar() {
  const pathname = usePathname()

  return (
    <div className="w-64 bg-card border-r border-gray-200 dark:border-gray-700 flex flex-col">
      {/* Logo Section */}
      <div className="p-6 border-b border-gray-200 dark:border-gray-700">
        <h1 className="text-xl font-bold text-gray-900 dark:text-gray-50">Real Estate Admin</h1>
      </div>

      {/* Navigation */}
      <nav className="flex-1 p-4 space-y-2">
        {navItems.map((item) => {
          // Determine if main item is active
          let isActive = false

          if (item.href) {
            isActive = pathname === item.href
          } else if (item.label === "Property") {
            // Property button highlighted on both /execution and /execution/[id] routes
            isActive = pathname.startsWith("/execution")
          }

          return (
            <NavItemComponent
              key={item.label}
              item={item}
              isActive={isActive}
              pathname={pathname}
            />
          )
        })}
      </nav>
    </div>
  )
}